    for (u64 i = 0; i < nb_bytes; i++) to[i] = from[i];
}
bool trusted_utils_equal_signatures(const u8* left, const u8* right) {
    for (u64 i = 0; i < SIG_SIZE_BYTES; i++)
        if (left[i] != right[i]) return false;
    return true;
}
